<?php

namespace App\Console\Commands;

use Illuminate\Console\Command;
use Modules\Announcement\Entities\Announcement;
use Modules\Announcement\Entities\AnnouncementType;
use App\Models\User;
use Carbon\Carbon;
use App\Services\FirebaseService;
use Google\Client as GoogleClient;
use GuzzleHttp\Client;

class CheckUserBirthdays extends Command
{
    /**
     * The name and signature of the console command.
     *
     * @var string
     */
    protected $signature = 'app:check-user-birthdays';

    /**
     * The console command description.
     *
     * @var string
     */
    protected $description = 'Check for users with birthdays today and create an announcement';

    /**
     * Execute the console command.
     */
    public function handle()
    {

        $this->info('[' . now() . '] Announcements creating started for today\'s birthdays & Work Anniversary.');

        // Get today's date
        $today = Carbon::today()->format('m-d');

        // Fetch users with birthdays today
        $users = User::where('status', User::STATUS_ACTIVE)->with('profile')
            ->whereHas('profile', function ($query) use ($today) {
                $query->whereRaw('DATE_FORMAT(date_of_birth, "%m-%d") = ?', [$today]);
            })
            ->get();
        // Fetch users with work anniversaries today
        // $workusers = User::where('status',User::STATUS_ACTIVE)->with('workDetail')
        //                 ->whereHas('workDetail', function ($query) use ($today) {
        //                     $query->whereRaw('DATE_FORMAT(joining_date, "%m-%d") = ?', [$today]);
        //                 })
        //                 ->get();
        $workusers = User::where('status', User::STATUS_ACTIVE)
            ->with('workDetail')
            ->whereHas('workDetail', function ($query) use ($today) {
                $query->whereRaw('DATE_FORMAT(joining_date, "%m-%d") = ?', [$today])
                    ->whereYear('joining_date', '<', now()->year); // exclude users who joined this year
            })
            ->get();


        $announcementType = AnnouncementType::Where('name', 'like', '%Birthday Announcement%')->first();
        if (!$announcementType) {
            $announcement = AnnouncementType::create([
                'name' => 'Birthday Announcement',
                'color' => '#168328'
            ]);
        }
        $workannouncementType = AnnouncementType::Where('name', 'like', '%Work Anniversary Announcement%')->first();
        if (!$workannouncementType) {
            $workannouncement = AnnouncementType::create([
                'name' => 'Work Anniversary Announcement',
                'color' => '#115891'
            ]);
        }
        if ($users->isNotEmpty()) {
            foreach ($users as $user) {
                $this->info('[' . now() . '] user: ' . json_encode($user));
                $alreadybrithdayExists = Announcement::where('is_added', $user->id)
                    ->where('announcement_type_id', $announcementType ? $announcementType->id : $announcement->id)
                    ->whereDate('start_at', Carbon::today())
                    ->exists();

                if (!$alreadybrithdayExists) {
                    // Create an announcement for each user with a birthday
                    Announcement::create([
                        'body' => '<p>Happy Brithday ' . $user->name . '! 🎉</p><p><br /></p><div style="text-align: center;"><img style="width: 100%;" src="data:image/jpeg;base64," /></div>',
                        'start_at' => Carbon::now(),
                        'end_at' => Carbon::now()->addHours(24),
                        'user_id' => null,
                        'is_added' => $user->id,
                        'announcement_type_id' => $announcementType ? $announcementType->id : $announcement->id,
                    ]);

                    if ($user->ftoken != null) {
                        $serviceAccountFile = base_path('WorkPilot-b588f-44a1ea5aa896.json');
                        $client = new GoogleClient();
                        $client->setAuthConfig($serviceAccountFile);
                        $client->addScope('https://www.googleapis.com/auth/firebase.messaging');
                        $accessTokenArray = $client->fetchAccessTokenWithAssertion();
                        $accessToken =  $accessTokenArray['access_token'] ?? null;

                        $url = 'https://fcm.googleapis.com/v1/projects/WorkPilot-b588f/messages:send';
                        $headers = [
                            'Authorization' => 'Bearer ' . $accessToken,
                            'Content-Type' => 'application/json',
                        ];
                        $data = [
                            'message' => [
                                'token' => $user->ftoken,
                                'notification' => [
                                    'title' => 'Reminder',
                                    'body' => 'Happy Brithday ' . $user->name . '! 🎉',
                                ],
                            ],
                        ];
                        try {
                            $httpClient =  new Client();
                            $response = $httpClient->post($url, [
                                'headers' => $headers,
                                'json' => $data,
                                'curl' => [
                                    CURLOPT_SSL_VERIFYPEER => false,
                                    CURLOPT_SSL_VERIFYHOST => false,
                                ],
                            ]);
                        } catch (RequestException $e) {
                            // \Log::error("Failed to send notification to user ID {$user->id}: " . $e->getMessage());
                            continue;
                        } catch (\Exception $e) {
                            // \Log::error("An error occurred for user ID {$user->id}: " . $e->getMessage());
                            continue;
                        }
                    }
                }
                sleep(10);
            }
        }

        if ($workusers->isNotEmpty()) {
            foreach ($workusers as $workuser) {
                $alreadyExists = Announcement::where('is_added', $workuser->id)
                    ->where('announcement_type_id', $workannouncementType ? $workannouncementType->id : $workannouncementType->id)
                    ->whereDate('start_at', Carbon::today())
                    ->exists();

                if (!$alreadyExists) {
                    // Create an announcement for each user with a birthday
                    Announcement::create([
                        'body' => '<p>Today`s ' . $workuser->name . ' Work Anniversary!</p><p><br /></p><div style="text-align: center;" __rte_selected_block=""><img style="max-width: 80%;" src="data:image/jpeg;base64,"></div>',
                        'start_at' => Carbon::now(),
                        'end_at' => Carbon::now()->addHours(24),
                        'user_id' => null,
                        'is_added' => $workuser->id,
                        'announcement_type_id' => $workannouncementType ? $workannouncementType->id : $workannouncement->id,
                    ]);

                    if ($workuser->ftoken != null) {
                        $serviceAccountFile = base_path('WorkPilot-b588f-44a1ea5aa896.json');
                        $client = new GoogleClient();
                        $client->setAuthConfig($serviceAccountFile);
                        $client->addScope('https://www.googleapis.com/auth/firebase.messaging');
                        $accessTokenArray = $client->fetchAccessTokenWithAssertion();
                        $accessToken =  $accessTokenArray['access_token'] ?? null;

                        $url = 'https://fcm.googleapis.com/v1/projects/WorkPilot-b588f/messages:send';
                        $headers = [
                            'Authorization' => 'Bearer ' . $accessToken,
                            'Content-Type' => 'application/json',
                        ];
                        $data = [
                            'message' => [
                                'token' => $workuser->ftoken,
                                'notification' => [
                                    'title' => 'Reminder',
                                    'body' => 'Today`s ' . $workuser->name . ' Work Anniversary!',
                                ],
                            ],
                        ];
                        try {
                            $httpClient =  new Client();
                            $response = $httpClient->post($url, [
                                'headers' => $headers,
                                'json' => $data,
                                'curl' => [
                                    CURLOPT_SSL_VERIFYPEER => false,
                                    CURLOPT_SSL_VERIFYHOST => false,
                                ],
                            ]);
                        } catch (RequestException $e) {
                            // \Log::error("Failed to send notification to workuser ID {$workuser->id}: " . $e->getMessage());
                            continue;
                        } catch (\Exception $e) {
                            // \Log::error("An error occurred for workuser ID {$workuser->id}: " . $e->getMessage());
                            continue;
                        }
                    }
                }
                sleep(10);
            }
        }
        $this->info('[' . now() . '] Announcements created for today\'s birthdays & Work Anniversary.');
    }
}
